What does this program print?

```cpp
#include <iostream>
#include <utility>

struct S {
    S() = default;
    S(S&&) noexcept { std::cout << "moved\n"; }
    S(const S&) { std::cout << "copied\n"; }
};

struct R {
    R() = default;
    R(R&&) { std::cout << "moved\n"; }
    R(const R&) { std::cout << "copied\n"; }
};

int main() {
    S s;
    S s2 = std::move_if_noexcept(s);
    R r;
    R r2 = std::move_if_noexcept(r);
    return 0;
}
```

